import React, { useState } from 'react';
import { FAQItem } from '../types';
import ReactMarkdown from 'react-markdown'; // Actually we don't have react-markdown in env, using simple rendering

interface Props {
  items: FAQItem[];
  title?: string;
}

const FAQ: React.FC<Props> = ({ items, title = "Perguntas Frequentes" }) => {
  const [openIndex, setOpenIndex] = useState<number | null>(0);

  const toggle = (index: number) => {
    setOpenIndex(openIndex === index ? null : index);
  };

  // Simple parser to handle bold text in markdown style **text**
  const renderText = (text: string) => {
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, index) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={index} className="text-secondary">{part.slice(2, -2)}</strong>;
      }
      return part;
    });
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl p-6 md:p-8">
      <h2 className="text-3xl font-bold text-center mb-8 text-primary">{title}</h2>
      <div className="space-y-4">
        {items.map((item, index) => (
          <div key={index} className="border border-gray-200 rounded-lg overflow-hidden">
            <button
              className={`w-full text-left p-4 md:p-5 flex justify-between items-center transition-colors ${
                openIndex === index ? 'bg-blue-50 text-secondary' : 'bg-white hover:bg-gray-50'
              }`}
              onClick={() => toggle(index)}
            >
              <span className="font-bold text-lg">{item.question}</span>
              <i className={`fas fa-chevron-down transition-transform duration-300 ${
                openIndex === index ? 'rotate-180' : ''
              }`}></i>
            </button>
            <div 
              className={`transition-all duration-300 ease-in-out overflow-hidden ${
                openIndex === index ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'
              }`}
            >
              <div className="p-5 text-gray-600 leading-relaxed border-t border-gray-100 bg-white">
                {renderText(item.answer)}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default FAQ;

import React, { useState } from 'react';

const ContactForm: React.FC = () => {
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    neighborhood: '',
    service: 'Desentupimento',
    message: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const text = `*Novo Contato do Site*%0A%0A*Nome:* ${formData.name}%0A*Telefone:* ${formData.phone}%0A*Bairro:* ${formData.neighborhood}%0A*Serviço:* ${formData.service}%0A*Mensagem:* ${formData.message}`;
    const url = `https://api.whatsapp.com/send?phone=5541985171966&text=${text}`;
    window.open(url, '_blank');
  };

  return (
    <div className="bg-gradient-to-br from-primary to-secondary p-8 rounded-2xl shadow-2xl text-white">
      <h3 className="text-2xl font-bold mb-2 text-center">Solicite um Orçamento</h3>
      <p className="text-center text-blue-100 mb-6">Resposta rápida via WhatsApp</p>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-semibold mb-1 ml-1">Seu Nome</label>
          <input 
            type="text" 
            name="name"
            required
            value={formData.name}
            onChange={handleChange}
            className="w-full px-4 py-3 rounded-lg text-gray-800 focus:outline-none focus:ring-2 focus:ring-accent"
            placeholder="Digite seu nome"
          />
        </div>

        <div>
          <label className="block text-sm font-semibold mb-1 ml-1">WhatsApp / Telefone</label>
          <input 
            type="tel" 
            name="phone"
            required
            value={formData.phone}
            onChange={handleChange}
            className="w-full px-4 py-3 rounded-lg text-gray-800 focus:outline-none focus:ring-2 focus:ring-accent"
            placeholder="(41) 99999-9999"
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold mb-1 ml-1">Bairro</label>
            <input 
              type="text" 
              name="neighborhood"
              value={formData.neighborhood}
              onChange={handleChange}
              className="w-full px-4 py-3 rounded-lg text-gray-800 focus:outline-none focus:ring-2 focus:ring-accent"
              placeholder="Ex: Água Verde"
            />
          </div>
          <div>
            <label className="block text-sm font-semibold mb-1 ml-1">Tipo de Serviço</label>
            <select 
              name="service"
              value={formData.service}
              onChange={handleChange}
