    ];
    const index = (name?.length || 0) % args.length;
    return args[index];
  }, [name]);

  const locationImage = useMemo(() => {
    const idx = (name?.length || 0) % IMAGES.length;
    return IMAGES[idx] || IMAGES[0];
  }, [name]);

