                          <p className="text-xs text-gray-500">{item.availability}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <FAQ 
                    items={[
                        { question: `Qual o valor da visita em ${titleName}?`, answer: `Em ${titleName}, a visita e o orçamento são **100% gratuitos**. O técnico avalia o problema e passa o valor na hora.` },
                        ...GENERAL_FAQ.slice(0, 2)
                    ]} 
                    title={`Dúvidas sobre ${titleName}`}
                />
            </div>

            <div className="w-full lg:w-1/3 space-y-8">
                <ContactForm />
                <div className="bg-urgent text-white p-8 rounded-2xl shadow-xl text-center">
                  <h4 className="text-xl font-bold mb-4">Emergência Agora?</h4>
                  <p className="mb-6 opacity-90 text-sm">Temos um técnico de plantão perto de {titleName}.</p>
                  <a href={CONTACT_INFO.whatsappLink} className="block bg-white text-urgent font-bold py-4 rounded-xl hover:scale-105 transition-all">
                    <i className="fab fa-whatsapp mr-2 text-xl"></i> CHAMAR WHATSAPP
                  </a>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default DynamicPage;

import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

const ImageGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('Professional plumber working in a modern house, high quality photography, cinematic lighting, 8k resolution, realistic details, Curitiba architecture style.');
  const [aspectRatio, setAspectRatio] = useState<'1:1' | '3:4' | '4:3' | '9:16' | '16:9'>('16:9');
  const [imageSize, setImageSize] = useState<'1K' | '2K' | '4K'>('1K');
  const [loading, setLoading] = useState(false);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [hasKey, setHasKey] = useState<boolean | null>(null);

  useEffect(() => {
    checkKey();
  }, []);

  const checkKey = async () => {
    try {
      // @ts-ignore
      if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasKey(selected);
      } else {
        setHasKey(false);
      }
    } catch (e) {
      setHasKey(false);
    }
  };

  const handleSelectKey = async () => {
    try {
      // @ts-ignore
      if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
        await window.aistudio.openSelectKey();
        setHasKey(true);
      } else {
        setError("Seletor de chaves indisponível.");
      }
    } catch (e) {
      setHasKey(true); 
    }
  };

  const generateImage = async () => {
    if (!prompt.trim()) {
      setError("Por favor, digite um prompt.");
      return;
    }

    setLoading(true);
    setError(null);
    setGeneratedImageUrl(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [{ text: prompt }],
        },
        config: {
          imageConfig: {
            aspectRatio: aspectRatio,
            imageSize: imageSize
          }
        },
      });

      let foundImage = false;
      const candidate = response.candidates?.[0];
      if (candidate?.content?.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            const base64Data = part.inlineData.data;
            setGeneratedImageUrl(`data:image/png;base64,${base64Data}`);
            foundImage = true;
            break;
          }
        }
      }

      if (!foundImage) {
        // Fallback for text response without image
        const textPart = candidate?.content?.parts.find(p => p.text);
        if (textPart) {
          setError(`A IA retornou apenas texto: ${textPart.text}`);
        } else {
          throw new Error("A imagem não pôde ser gerada.");
        }
      }
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("entity was not found")) {
        setError("Chave de API inválida ou projeto sem faturamento ativo.");
        setHasKey(false);
      } else {
        setError(`Erro: ${err.message || "Falha na comunicação com o servidor Gemini."}`);
      }
    } finally {
      setLoading(false);
    }
  };

  if (hasKey === false) {
    return (
      <div className="min-h-[70vh] flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-10 text-center border border-gray-100">
